import { Component, computed } from '@angular/core';
import { CommonModule } from '@angular/common';
import { ActivatedRoute } from '@angular/router';
import { SiteviewService } from '../../../core/services/siteview.service';

interface Pt { x: number; y: number; }
interface PhasePoint {
  phaseId: string;
  name: string;
  order: number;
  planned: number;
  actual: number;
  cumPlanned: number;
  cumActual: number;
  over: boolean;
  planPt: Pt;
  actPt: Pt;
}
interface BudgetChart {
  width: number;
  height: number;
  points: PhasePoint[];
  plannedLine: string;
  actualLine: string;
  actualArea: string;
  gridY: Array<{ y: number; label: string }>;
  totalPlanned: number;
  totalActual: number;
}

const W = 680;
const H = 300;
const M = { top: 20, right: 20, bottom: 40, left: 64 };

@Component({
  selector: 'app-budget',
  standalone: true,
  imports: [CommonModule],
  templateUrl: './budget.component.html',
  styleUrl: './budget.component.css',
})
export class BudgetComponent {
  private readonly projectId = this.route.parent?.snapshot.paramMap.get('id') ?? '';

  readonly chart = computed<BudgetChart>(() => {
    const phases = this.sv.phasesForProject(this.projectId);
    const plotW = W - M.left - M.right;
    const plotH = H - M.top - M.bottom;

    let cumP = 0;
    let cumA = 0;
    const raw = phases.map((ph) => {
      const lines = this.sv.budgetLines().filter((b) => b.phaseId === ph.id);
      const planned = lines.reduce((s, l) => s + l.plannedCents, 0);
      const actual = lines.reduce((s, l) => s + l.actualCents, 0);
      cumP += planned;
      cumA += actual;
      return { ph, planned, actual, cumPlanned: cumP, cumActual: cumA };
    });

    const maxY = Math.max(1, cumP, cumA);
    const n = Math.max(1, raw.length);
    const xFor = (i: number) => M.left + (n === 1 ? plotW / 2 : (i / (n - 1)) * plotW);
    const yFor = (v: number) => M.top + plotH - (v / maxY) * plotH;

    const points: PhasePoint[] = raw.map((r, i) => ({
      phaseId: r.ph.id,
      name: r.ph.name,
      order: r.ph.order,
      planned: r.planned,
      actual: r.actual,
      cumPlanned: r.cumPlanned,
      cumActual: r.cumActual,
      over: r.actual > r.planned,
      planPt: { x: xFor(i), y: yFor(r.cumPlanned) },
      actPt: { x: xFor(i), y: yFor(r.cumActual) },
    }));

    const plannedLine = points.map((p) => `${p.planPt.x},${p.planPt.y}`).join(' ');
    const actualLine = points.map((p) => `${p.actPt.x},${p.actPt.y}`).join(' ');
    const baseY = M.top + plotH;
    const actualArea = points.length
      ? `${points[0].actPt.x},${baseY} ` +
        points.map((p) => `${p.actPt.x},${p.actPt.y}`).join(' ') +
        ` ${points[points.length - 1].actPt.x},${baseY}`
      : '';

    const gridY = [0, 0.25, 0.5, 0.75, 1].map((f) => ({
      y: yFor(maxY * f),
      label: this.usdShort(maxY * f),
    }));

    return {
      width: W,
      height: H,
      points,
      plannedLine,
      actualLine,
      actualArea,
      gridY,
      totalPlanned: cumP,
      totalActual: cumA,
    };
  });

  constructor(
    private sv: SiteviewService,
    private route: ActivatedRoute,
  ) {}

  usd(cents: number): string {
    return (cents / 100).toLocaleString('en-US', { style: 'currency', currency: 'USD', maximumFractionDigits: 0 });
  }
  usdShort(cents: number): string {
    const d = cents / 100;
    if (d >= 1_000_000) return `$${(d / 1_000_000).toFixed(1)}M`;
    if (d >= 1_000) return `$${Math.round(d / 1_000)}k`;
    return `$${Math.round(d)}`;
  }
}
